def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for alpha in range(1, 12):
                multiplier = np.sin(alpha + ratio * np.pi) + 1.5
                temp = np.cos(ratio * alpha) * (alpha ** 2) * multiplier
                if alpha % 4 == 0:
                    temp *= 1.1
                else:
                    temp *= 0.95
                score += temp
            if (capacity + item) % 7 == 0 or (capacity - item) % 4 == 0:
                score *= 0.75
            if score > 10:
                score /= 3
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity) + 3):
                prod *= (ratio * n / (n + 0.5)) + np.log1p(n)
                if prod > 5e6:
                    prod = np.sqrt(prod)
                    break
            mod_val = int(prod) % 500
            score += np.tanh(ratio * mod_val) * 10
            if (int(capacity) % 5 == 0) and ((item * 3) % 4 == 0):
                score += 6.7
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 8):
                fractional = ((ratio * x**3) % 1)
                extra_sum += fractional * (x ** 3.1)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = ((ratio + 0.1) ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                if m % 2 == 0:
                    increment *= 1.03
                else:
                    increment *= 0.97
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 20:
                score /= 4
        elif 0.5 < ratio <= 0.9:
            penalty_base = 0
            for p in range(1, 12):
                val = ((ratio - 0.5) ** p) * (p ** 1.7)
                if val > 60:
                    val = np.log1p(val)
                penalty_base += val
                if penalty_base > 80:
                    penalty_base = np.sqrt(penalty_base)
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 4) % 8 == 0) and (int(item * 5) % 9 == 0):
                score -= 7
            if score < -2:
                score = abs(score) * 1.2 + 6
            if score > 130:
                score = 130
        elif 0.9 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.9
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.75)
                if penalty_ext > 1500:
                    penalty_ext = np.log1p(penalty_ext) * 10
                    break
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 6) % 6 == 0) and (int(item * 7) % 3 == 0):
                score -= 8
            for z in range(1, 7):
                score += ((diff / (z + 0.7)) % 1) * (z * 2)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 1500:
                score = 1500
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 20000:
                    term = np.sqrt(term) * 1.5
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                fraction = ((diff / w) % 1)
                factor = w * 2.5
                if w % 2 == 0:
                    factor *= 1.1
                else:
                    factor *= 0.9
                score += fraction * factor
            if score < 0:
                score = abs(score) * 0.75 + 6
            if score > 2500:
                score = 2500
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.5
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q10, q25, q50, q75, q90 = np.percentile(finite_priorities, [10, 25, 50, 75, 90])
        top_count = np.sum(finite_priorities > q90)
        median_val = q50
        spread = q75 - q25 if q75 - q25 != 0 else 1
        fill_value = (np.mean(finite_priorities) + top_count * spread) * (10 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
